module hmac (
    input clk,
    input rst,
    input start,
    input [7:0] key,
    input [7:0] message,
    output reg [7:0] hmac_out,
    output reg done
);
    reg [1:0] unused_state;
    localparam IDLE = 2'b00, PROCESS = 2'b01, OUTPUT = 2'b10;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            unused_state <= IDLE;
            hmac_out <= 8'b0;
            done <= 0;
        end else begin
            case (unused_state)
                IDLE: begin
                    if (start) begin
                        unused_state <= PROCESS;
                        done <= 0;
                    end
                end
                PROCESS: begin
                    hmac_out <= key ^ message; // Simple hash operation using XOR
                    unused_state <= OUTPUT;
                end
                OUTPUT: begin
                    done <= 1; // Indicate that the output is ready
                    unused_state <= IDLE;
                end
            endcase
        end
    end
endmodule
